from typing import TYPE_CHECKING

from .prompt_router_config import build_action_intent_routes, build_exact_direct_routes
from .prompt_router_routing import MavaliEthPromptRoutingMixin

if TYPE_CHECKING:
    from .service import MavaliEthService


class MavaliEthPromptRouter(MavaliEthPromptRoutingMixin):
    def __init__(self, service: "MavaliEthService") -> None:
        self.service = service
        self._action_intent_routes = build_action_intent_routes(service)
        self._exact_direct_routes = build_exact_direct_routes(service)

    def handle_prompt(
        self,
        session_key: str,
        prompt: str,
        *,
        actor_chat_id: int | None = None,
        actor_user_id: int | None = None,
    ) -> str:
        text = self.service.runtime.extract_current_message_text(prompt)
        if not text:
            return self.service.wallet_queries.help_message()
        lowered = text.lower()

        direct_message = self._route_direct_commands(
            session_key,
            lowered,
            actor_chat_id=actor_chat_id,
            actor_user_id=actor_user_id,
        )
        if direct_message is not None:
            return direct_message

        polymarket_message = self._route_polymarket_queries(
            session_key,
            text,
            actor_chat_id=actor_chat_id,
            actor_user_id=actor_user_id,
        )
        if polymarket_message is not None:
            return polymarket_message

        wallet_message = self._route_wallet_queries(text, lowered)
        if wallet_message is not None:
            return wallet_message

        utility_message = self._route_utility_queries(text, lowered)
        if utility_message is not None:
            return utility_message

        action_message = self._route_action_intents(
            session_key,
            text,
            actor_chat_id=actor_chat_id,
            actor_user_id=actor_user_id,
        )
        if action_message is not None:
            return action_message

        return self.service.wallet_queries.help_message()
