def build_exact_direct_routes(service) -> dict[str, Callable[..., str]]:
    routes: dict[str, Callable[..., str]] = {}

    def register(prompts: tuple[str, ...], handler: Callable[..., str]) -> None:
        for prompt in prompts:
            routes[prompt] = handler

    register(("show portfolio", "show unified portfolio"), service.portfolio_message)
    register(("show aster account",), service.aster_account_message)
    register(("show hyperliquid account",), service.hyperliquid_account_message)
    register(
        ("show hyperliquid balances", "show hyperliquid balance"),
        service.hyperliquid_balances_message,
    )
    register(
        ("show hyperliquid spot balances", "show hyperliquid spot balance"),
        service.hyperliquid_spot_balances_message,
    )
    register(
        ("show hyperliquid deposit address", "show hyperliquid eth deposit address"),
        service.hyperliquid_deposit_route_message,
    )
    register(
        (
            "show hyperliquid funding operations",
            "show hyperliquid recent funding operations",
            "show hyperliquid deposit operations",
        ),
        service.hyperliquid_funding_operations_message,
    )
    register(
        ("show hyperliquid funding", "show hyperliquid deposit route"),
        service.hyperliquid_funding_message,
    )
    register(
        ("show hyperliquid withdrawal route", "show hyperliquid eth withdrawal route"),
        service.hyperliquid_withdrawal_route_message,
    )
    register(
        (
            "show hyperliquid withdrawal operations",
            "show hyperliquid recent withdrawal operations",
        ),
        service.hyperliquid_withdrawal_operations_message,
    )
    register(
        ("show hyperliquid withdrawal", "show hyperliquid withdraw"),
        service.hyperliquid_withdrawal_message,
    )
    register(
        ("show aster balances", "show aster balance"),
        service.aster_balances_message,
    )
    register(
        ("show aster spot balances", "show aster spot balance"),
        service.aster_spot_balances_message,
    )
    register(
        ("show aster margin", "show aster account margin"),
        service.aster_margin_message,
    )
    register(
        ("show aster positions", "show aster position"),
        service.aster_positions_message,
    )
    register(
        ("show aster controls", "show aster account controls"),
        service.aster_controls_message,
    )
    return routes
