    def _route_polymarket_queries(
        self,
        session_key: str,
        text: str,
        *,
        actor_chat_id: int | None = None,
        actor_user_id: int | None = None,
    ) -> Optional[str]:
        try:
            polymarket_limit = parse_polymarket_list_query(text)
        except ValueError as exc:
            return str(exc)
        if polymarket_limit is not None:
            return self.service.polymarket_queries.markets_message(polymarket_limit)

        polymarket_market_query = parse_polymarket_market_query(text)
        if polymarket_market_query is not None:
            return self.service.polymarket_queries.market_message(polymarket_market_query)

        try:
            polymarket_search_query = parse_polymarket_search_query(text)
        except ValueError as exc:
            return str(exc)
        if polymarket_search_query is not None:
            query, limit = polymarket_search_query
            return self.service.polymarket_queries.search_message(query, limit)

        try:
            polymarket_positions_query = parse_polymarket_positions_query(text)
        except ValueError as exc:
            return str(exc)
        if polymarket_positions_query is not None:
            mode, limit = polymarket_positions_query
            return self.service.polymarket_queries.positions_message(closed=(mode == "closed"), limit=limit)

        if parse_polymarket_value_query(text):
            return self.service.polymarket_queries.value_message()

        if parse_polymarket_account_query(text):
            return self.service.polymarket_queries.account_message()

        if parse_polymarket_orders_query(text):
            return self.service.polymarket_queries.orders_message()

        if parse_polymarket_trades_query(text):
            return self.service.polymarket_queries.trades_message()

        polymarket_orderbook_query = parse_polymarket_orderbook_query(text)
        if polymarket_orderbook_query is not None:
            return self.service.polymarket_queries.orderbook_message(polymarket_orderbook_query)

        try:
            polymarket_order_preview_query = parse_polymarket_order_preview_query(text)
        except ValueError as exc:
            return str(exc)
        if polymarket_order_preview_query is not None:
            return self.service.prepare_polymarket_order_preview_action(
                session_key,
                side=polymarket_order_preview_query.side,
                amount_display=polymarket_order_preview_query.amount_display,
                outcome=polymarket_order_preview_query.outcome,
                market_identifier=polymarket_order_preview_query.market_identifier,
                actor_chat_id=actor_chat_id,
                actor_user_id=actor_user_id,
            )

        return None

    def _route_wallet_queries(self, text: str, lowered: str) -> Optional[str]:
        stripped = lowered.strip()
        try:
            token_balance_query = parse_token_balance_query(text)
        except AddressParseError as exc:
            return str(exc)
        if token_balance_query:
            return self.service.wallet_queries.token_balance_message(token_balance_query)

        try:
            token_allowance_query = parse_token_allowance_query(text)
        except AddressParseError as exc:
            return str(exc)
        if token_allowance_query:
            token_address, spender_address = token_allowance_query
            return self.service.wallet_queries.token_allowance_message(token_address, spender_address)

        if any(token in lowered for token in ("aster", "hyperliquid", "polymarket")):
            return None

        if (
            stripped in {"balance", "whats the balance", "what is the balance", "what's the balance"}
            or "eth balance" in lowered
            or "wallet balance" in lowered
            or re.search(r"\bwhat(?:'s| is)(?: my)? balance\b", lowered) is not None
        ):
            return self.service.wallet_queries.wallet_balance_message()

        return None

    def _route_utility_queries(self, text: str, lowered: str) -> Optional[str]:
        gwei_conversion = self.service.wallet_queries.eth_to_gwei_message(text)
        if gwei_conversion:
            return gwei_conversion

        if "gas" in lowered and any(token in lowered for token in ("need", "how much", "fund")):
            return self.service.wallet_queries.funding_guidance_message()

        return None
