                    credential_kind="api_key",
                    status="active",
                    created_at=100.0,
                    payload={"api_key": "hidden", "api_secret": "hidden"},
                )
            )
            text = service.handle_prompt("telegram:1", "backburner buy XAGUSDT 1h total 30000")
            self.assertIn("Backburner armed.", text)
