            prices = [Decimal(str(item["price"])) for item in fake_aster.placed_orders]
            self.assertGreater(prices[0], prices[1])
            self.assertGreater(prices[1], prices[2])
            strategy_state = active_backburner_state(store, "XAGUSDT")
