    def _route_action_intents(
        self,
        session_key: str,
        text: str,
        *,
        actor_chat_id: int | None = None,
        actor_user_id: int | None = None,
    ) -> Optional[str]:
        for route in self._action_intent_routes:
            try:
                intent = route.parser(text)
            except route.error_types as exc:
                return str(exc)
            if intent is None:
                continue
            try:
                return route.handler(
                    session_key,
                    intent,
                    actor_chat_id=actor_chat_id,
                    actor_user_id=actor_user_id,
                )
            except RuntimeError as exc:
                if route.catch_runtime:
                    return str(exc)
                raise

        return None
